import React, { useEffect, useState } from "react";
import {
  Search,
  Heart,
  Share2,
  Copy,
  RefreshCw,
  Filter,
  Shuffle,
} from "lucide-react";
import quotesData from "../data/quotes.json";

type Verse = {
  Emotion?: string;
  Reference: string;
  Verse: string;
};

type QuotesAppProps = {
  theme: "light" | "dark";
  setTheme: React.Dispatch<React.SetStateAction<"light" | "dark">>;
};

const QuotesApp: React.FC<QuotesAppProps> = ({ theme }) => {
  const [versesData, setVersesData] = useState<Verse[]>([]);
  const [selectedEmotion, setSelectedEmotion] = useState("");
  const [searchKeyword, setSearchKeyword] = useState("");
  const [displayVerse, setDisplayVerse] = useState<Verse | null>(null);
  const [favorites, setFavorites] = useState<Verse[]>([]);
  const [showFavorites, setShowFavorites] = useState(false);

  useEffect(() => {
    setVersesData(quotesData);
  }, []);

  const handleSearch = () => {
    let filtered = versesData;

    if (selectedEmotion) {
      filtered = filtered.filter((v) => v.Emotion === selectedEmotion);
    }
    if (searchKeyword) {
      filtered = filtered.filter((v) =>
        v.Verse.toLowerCase().includes(searchKeyword.toLowerCase())
      );
    }

    if (filtered.length > 0) {
      setDisplayVerse(filtered[Math.floor(Math.random() * filtered.length)]);
    } else {
      setDisplayVerse(null);
    }
  };

  const handleRandom = () => {
    if (versesData.length > 0) {
      setDisplayVerse(
        versesData[Math.floor(Math.random() * versesData.length)]
      );
    }
  };

  const toggleFavorite = (verse: Verse) => {
    setFavorites((prev) =>
      prev.some((f) => f.Reference === verse.Reference)
        ? prev.filter((f) => f.Reference !== verse.Reference)
        : [...prev, verse]
    );
  };

  return (
    <div
      className={`min-h-screen px-6 py-8 ${
        theme === "light" ? "bg-gray-100 text-gray-800" : "bg-gray-800 text-white"
      }`}
    >
      {/* Search and Filters */}
      <div className="flex flex-col md:flex-row items-center gap-4 mb-6">
        <input
          type="text"
          placeholder="Search keyword..."
          value={searchKeyword}
          onChange={(e) => setSearchKeyword(e.target.value)}
          className="border rounded px-3 py-2 w-full md:w-1/3 text-black"
        />

        <select
          value={selectedEmotion}
          onChange={(e) => setSelectedEmotion(e.target.value)}
          className="border rounded px-3 py-2 text-black"
        >
          <option value="">All Emotions</option>
          <option value="Hope">Hope</option>
          <option value="Faith">Faith</option>
          <option value="Love">Love</option>
          {/* add more emotions from your JSON */}
        </select>

        <button
          onClick={handleSearch}
          className="flex items-center gap-2 bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
        >
          <Search size={18} /> Search
        </button>

        <button
          onClick={handleRandom}
          className="flex items-center gap-2 bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600"
        >
          <Shuffle size={18} /> Random
        </button>
      </div>

      {/* Verse Display */}
      {displayVerse && (
        <div
          className={`p-6 rounded-lg shadow-md mb-6 ${
            theme === "light" ? "bg-white" : "bg-gray-700"
          }`}
        >
          <p className="text-lg italic mb-2">"{displayVerse.Verse}"</p>
          <p className="font-semibold">- {displayVerse.Reference}</p>
          <div className="flex items-center gap-4 mt-3">
            <button
              onClick={() => toggleFavorite(displayVerse)}
              className="flex items-center gap-1 text-red-500 hover:text-red-600"
            >
              <Heart size={18} />
              {favorites.some((f) => f.Reference === displayVerse.Reference)
                ? "Unfavorite"
                : "Favorite"}
            </button>
            <button className="flex items-center gap-1 text-blue-500 hover:text-blue-600">
              <Copy size={18} /> Copy
            </button>
            <button className="flex items-center gap-1 text-green-500 hover:text-green-600">
              <Share2 size={18} /> Share
            </button>
          </div>
        </div>
      )}

      {/* Favorites */}
      <button
        onClick={() => setShowFavorites(!showFavorites)}
        className="flex items-center gap-2 bg-purple-500 text-white px-4 py-2 rounded hover:bg-purple-600"
      >
        <Heart size={18} />
        {showFavorites ? "Hide Favorites" : "Show Favorites"}
      </button>

      {showFavorites && (
        <div className="mt-4 space-y-4">
          {favorites.length > 0 ? (
            favorites.map((fav, i) => (
              <div
                key={i}
                className={`p-4 rounded shadow ${
                  theme === "light" ? "bg-white" : "bg-gray-700"
                }`}
              >
                <p className="italic">"{fav.Verse}"</p>
                <p className="font-semibold">- {fav.Reference}</p>
              </div>
            ))
          ) : (
            <p className="italic text-gray-500">No favorites yet.</p>
          )}
        </div>
      )}
    </div>
  );
};

export default QuotesApp;
